        let yroot = self.find(y);
        if xroot == yroot {
            return;
        }
        if self.rank[xroot] < self.rank[yroot] {
            self.parent[xroot] = yroot;
        } else {
            self.parent[yroot] = xroot;
            if self.rank[xroot] == self.rank[yroot] {
                self.rank[xroot] += 1;
            }
        }
        self.count -= 1;
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    if k == 1 {
        let max_w = edges.iter().map(|e| e[2]).max().unwrap_or(0);
        return max_w;
    }

    let mut edges = edges;
    edges.sort_by(|a, b| a[2].cmp(&b[2]));

    let mut low = 1;
    let mut high = if edges.is_empty() { 0 } else { edges.last().unwrap()[2] };
    let mut answer = high;

    while low <= high {
        let mid = (low + high) / 2;
        let mut dsu = DSU::new(n as usize);
        for edge in &edges {
            if edge[2] <= mid {
                dsu.union(edge[0] as usize, edge[1] as usize);
            }
        }
        if dsu.count <= k {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    answer
}
