    rank: Vec<i64>,
    count: i64,
}

impl DSU {
    fn new(n: i64) -> Self {
        let parent: Vec<i64> = (0..n).map(|x| x as i64).collect();
        let rank: Vec<i64> = (0..n).map(|x| 1).collect();
        DSU { parent, rank, count: n }
    }

    fn find(&mut self, x: i64) -> i64 {
        if self.parent[x as usize] != x {
            self.parent[x as usize] = self.find(self.parent[x as usize]);
        }
        self.parent[x as usize]
    }

    fn union(&mut self, x: i64, y: i64) {
        let xroot = self.find(x);
        let yroot = self.find(y);
        if xroot == yroot {
            return;
        }
        if self.rank[xroot as usize] < self.rank[yroot as usize] {
            self.parent[xroot as usize] = yroot;
        } else {
            self.parent[yroot as usize] = xroot;
            if self.rank[xroot as usize] == self.rank[yroot as usize] {
