#include <vector>
#include <algorithm>

using namespace std;

struct DSU {
    vector<int> parent;
    vector<int> rank;
    int count;
    DSU(int n) {
        parent.resize(n);
        rank.resize(n);
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
            rank[i] = 1;
        }
        count = n;
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void union_(int x, int y) {
        int xroot = find(x);
        int yroot = find(y);
        if (xroot == yroot) return;
        if (rank[xroot] < rank[yroot]) {
            parent[xroot] = yroot;
        } else {
            parent[yroot] = xroot;
            if (rank[xroot] == rank[yroot]) {
                rank[xroot]++;
            }
        }
        count--;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (k == 1) {
        long long max_w = 0;
        for (auto& e : edges) {
            max_w = max(max_w, e[2]);
        }
        return max_w;
