    long long low = 1;
    long long high = edges.back()[2];
    long long answer = high;
    while (low <= high) {
        long long mid = (low + high) / 2;
        DSU dsu(n);
        for (auto& e : edges) {
            if (e[2] <= mid) {
                dsu.union_(e[0], e[1]);
            }
        }
        if (dsu.count <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}
